import {pool} from '../infra/pg';
import {io} from '../server';
export async function executeDrop(dropId:number){
  const client=await pool.connect();
  try{await client.query('BEGIN');await client.query('SELECT pg_advisory_xact_lock($1)',[dropId]);
    const d=await client.query('SELECT status FROM drops WHERE id=$1 FOR UPDATE',[dropId]);
    if(d.rows[0].status!=='live'){await client.query('ROLLBACK');return;}
    const winner=await client.query(`SELECT bidder_id,max_cents FROM queued_bids WHERE drop_id=$1 ORDER BY queued_at ASC LIMIT 1`,[dropId]);
    if(winner.rows[0]){await client.query("UPDATE drops SET status='won',winner_id=$1 WHERE id=$2",[winner.rows[0].bidder_id,dropId]);}
    else await client.query("UPDATE drops SET status='expired' WHERE id=$1",[dropId]);
    await client.query('COMMIT');
    io.of('/drop').to(`drop:${dropId}`).emit('dropped',{winnerId:winner.rows[0]?.bidder_id});
  }catch(e){await client.query('ROLLBACK');throw e;}finally{client.release();}
}
