  await pool.query('INSERT INTO replication_log(order_id,from_region,payload) VALUES ($1,$2,$3)',[orderId,process.env.REGION,patch]);
  for(const region of (process.env.OTHER_REGIONS||'').split(',')){fetch(`https://${region}/api/replica/apply`,{method:'POST',body:JSON.stringify({orderId,patch,fromRegion:process.env.REGION,version:r.rows[0].version})}).catch(()=>{});}
