}
export async function applyRemote(orderId:string,patch:any,fromRegion:string,version:number){
  // LWW: only apply if remote version higher OR same with lex region tiebreak
  const cur=await pool.query('SELECT version,region FROM orders WHERE id=$1',[orderId]);
  if(cur.rows[0]&&(version<cur.rows[0].version||(version===cur.rows[0].version&&fromRegion<=cur.rows[0].region)))return;
  await pool.query('INSERT INTO orders(id,region,status,total_cents,updated_at,version) VALUES ($1,$2,$3,$4,now(),$5) ON CONFLICT (id) DO UPDATE SET region=EXCLUDED.region,status=EXCLUDED.status,total_cents=EXCLUDED.total_cents,updated_at=now(),version=EXCLUDED.version',[orderId,fromRegion,patch.status,patch.totalCents,version]);
  io.of('/replica').to(`order:${orderId}`).emit('update',{orderId,...patch,version});
}
